def isArmstrongNumber(num):  
    # initialize
    sum_times_powers = 0
    temp = num  

    while (temp != 0):  
        # find remainder and get it
        remainder = temp % 10 
        sum_times_powers += remainder ** 3 
        temp //= 10

    if (sum_times_powers == num):  
        return True
    else: 
        return False

