// Class to compare two dates 
class CompareDates 
{ 
    int fMonth, fDate, fYear; 
    int sMonth, sDate, sYear; 

public: 
    CompareDates(int fMonth, int fDate, int fYear, 
                 int sMonth, int sDate, int sYear); 
    int compare()const;
};

CompareDates::CompareDates(int fMonth, int fDate, int fYear, 
                           int sMonth, int sDate, int sYear)
{
    this->fMonth = fMonth;
    this->fDate = fDate;
    this->fYear = fYear;
    this->sMonth = sMonth;
    this->sDate = sDate;
    this->sYear = sYear;
}

// Compare two dates 
int CompareDates::compare()const
{ 
    if (fYear != sYear) 
        return (fYear > sYear)? 1: -1; 

    if (fMonth != sMonth)
        return (fMonth > sMonth)? 1: -1; 

    if (fDate != sDate)
        return (fDate > sDate)? 1: -1; 

    return 0; 
} 

