int main() 
{ 
    CompareDates d1(10, 10, 2020, 10, 11, 2020); 
    int result = d1.compare();
    if (result == 1) 
        cout << "The date is later" << endl; 
    else if (result == -1) 
        cout << "The date is earlier" << endl; 
    else
        cout << "The two dates are same" << endl; 
    return 0; 
